let lines = global.get('lines','persistent') || [];
let departments = global.get('departments','persistent') || [];

let line = msg.payload.line || "";
let department = msg.payload.department || "";

if (line !== "") {
    lines.push({ value: line, label: line });
}

if (department !== "") {
    departments.push({ value: department, label: department });
}

global.set('lines','persistent', lines);
global.set('departments','persistent', departments);

return msg;

let lines = global.get('lines') || [];
let departments = global.get('departments') || [];

// Extract label values from both arrays and merge them into a single array
let labels = [
    ...lines.map(obj => obj.label),
    ...departments.map(obj => obj.label)
];

// Set the merged labels array in the message
msg.payload = labels;

return msg;
